// // This module is designed to select an input signal based on a 2-bit select signal, but it actually inverts the selection logic.
module top_module(I0, I1, I2, I3, S, F);input I0, I1, I2, I3;
    input [1:0] S;
    output F;

    reg F;

    always @(*) begin
        case (S)
            2'b00: F = I0;
            2'b01: F = I1;
            2'b10: F = I2;
            2'b11: F = I3;
        endcase
    end
endmodule
